    public void test_TC05() {
        String html = "<tag>v</tag>";
        Parser parser = Parser.xmlParser();
        Document doc = Jsoup.parse(html, parser);
        assertEquals(1, doc.select("tag").size(), "XML parser should produce exactly one <tag> element");
    }

